864	// 폴더(scope)만 적용한 행 — 컨텍스트 분모/폴더 범위 계산용. folder가 null이면 전체. (kind 공용)
865	function mxScopedRows(kind) {
866	  const st = mxState[kind];
867	  const rows = (st.data && st.data.rows) || [];
868	  if (st.folder) return rows.filter((r) => r.scope === st.folder);
869	  return rows;
870	}
