872	// 현재 폴더·상태 필터·검색·태그로 걸러진 뒤, 미동기화 상단 정렬한 행.
873	function mxVisibleRows(kind) {
874	  const st = mxState[kind];
875	  const f = MX_FILTERS.find((x) => x.key === st.filter) || MX_FILTERS[1];
876	  const q = (st.q || '').trim().toLowerCase();
877	  const filtered = mxScopedRows(kind).filter((r) => {
878	    if (f.states && !f.states.includes(r.syncState)) return false;
879	    if (q && !String(r.name).toLowerCase().includes(q)) return false;
880	    if (!tagMatch(r)) return false; // 다중 태그(OR) 필터 연동
881	    return true;
882	  });
883	  // F4: 미동기화 상단 정렬(drift→partial→single→synced). 동률이면 이름순(안정적 표시).
884	  return filtered.slice().sort((a, b) => {
885	    const oa = MX_STATE_ORDER[a.syncState] ?? 9, ob = MX_STATE_ORDER[b.syncState] ?? 9;
886	    if (oa !== ob) return oa - ob;
887	    return a.name < b.name ? -1 : a.name > b.name ? 1 : 0;
888	  });
889	}
