891	// 도구 열 셀: 존재 시 ✓ + 그룹 색점(같은 색=내용 동일), 없으면 ✗.
892	// F5(agent): nonstandard(도구가 읽지 않는 위치의 파일) → "⚠ 비표준" 배지(툴팁)로 은은히 구분.
893	function mxToolCell(slot) {
894	  if (slot && slot.exists) {
895	    return `<span class="mx-cell-yes">✓<span class="mx-dot ${syncGroupClass(slot.group)}"></span></span>`;
896	  }
897	  if (slot && slot.nonstandard) {
898	    return `<span class="mx-cell-nonstd" title="이 도구가 읽지 않는 위치입니다(비표준)">⚠ 비표준</span>`;
899	  }
900	  return '<span class="mx-cell-no">✗</span>';
901	}
902	
903	// 경로 셀: 폴더명(전역이면 "전역(~)")만 표시, title에 전체 경로.
904	function mxScopeCell(r) {
905	  if (r.scope === 'global') return `<span class="mx-scope global" title="전역 홈(~)">전역(~)</span>`;
906	  const folder = baseName(r.scope);
907	  return `<span class="mx-scope" title="${esc(r.scope)}">📁 <span class="mxs-folder">${esc(folder)}</span></span>`;
908	}
909	
910	// 동기화 열: 상태 배지 + (단독·동기화됨이 아니면) [동기화] 버튼. 단독도 "다른 도구로 보내기"용 [동기화] 노출.
911	function mxSyncCell(kind, r) {
912	  const s = MX_SYNC[r.syncState] || MX_SYNC.single;
913	  const badge = `<span class="badge ${s.badge}">${s.ic} ${esc(s.ko)}</span>`;
914	  // 동기화됨은 이미 일치 → 버튼 없이 상태만. 나머지(불일치/일부없음/단독)는 [동기화] 노출.
915	  // data-sync-source는 생략: skill의 sourceId는 서버가 baseTool→공식 소스로 정확히 유도한다
916	  //   (임의 도구명을 sourceId로 넘기면 skillPull이 소스를 못 찾음). 기준 도구 자동선택은
917	  //   sync 모달이 lastSyncBase/baseCandidates로 처리한다.
918	  const btn = r.syncState === 'synced' ? ''
919	    : `<button class="btn btn-secondary btn-sm" data-sync-open="${kind}" data-sync-name="${esc(r.name)}">동기화</button>`;
920	  return `<div class="mx-sync">${badge}${btn}</div>`;
921	}
922	
923	// 행에서 존재하는 첫 도구 = 배치/단건 동기화 기본 기준(base).
924	function mxRowBase(r) {
925	  return TOOLS.find((t) => r.tools[t] && r.tools[t].exists) || 'claude';
926	}
