928	function renderMatrix(kind) {
929	  const st = mxState[kind];
930	  const body = $('#' + kind + '-mx-rows');
931	  if (!body) return;
932	  applyScopeColumn(kind); // 경로 컬럼 노출은 [전체] 선택 시에만 (skill·agent 공용)
933	  const all = mxVisibleRows(kind);
934	  renderMxContext(kind, all.length);
935	  const shown = all.slice(0, st.page * MX_PAGE);
936	  if (!all.length) {
937	    const empty = (st.data && (st.data.rows || []).length)
938	      ? '조건에 맞는 항목이 없습니다 — 필터/검색을 바꿔보세요'
939	      : `아직 ${kind === 'skill' ? '스킬' : '에이전트'}이 하나도 없어요 — 스토어에서 가져오거나 프로젝트를 추가해 보세요
940	        <span class="inline-acts" style="justify-content:center;margin-top:10px">
941	          <button class="btn btn-secondary btn-sm" data-goto="store">스토어 보기</button>
942	          <button class="btn btn-ghost btn-sm" data-open-projects="1">📁 프로젝트 관리</button>
943	        </span>`;
944	    body.innerHTML = `<tr><td colspan="${mxColspan(kind)}" class="skel">${empty}</td></tr>`;
945	    if ($('#' + kind + '-mx-more')) $('#' + kind + '-mx-more').innerHTML = '';
946	    const allc = $('#' + kind + '-mx-all'); if (allc) allc.checked = false;
947	    return;
948	  }
949	  body.innerHTML = shown.map((r) => {
950	    const rowErr = r.error ? ` <span class="badge warn" title="${esc(r.error)}">⚠ 이슈</span>` : '';
951	    return `<tr class="mx-row-${esc(r.syncState)}" data-mx-row="${kind}" data-mx-name="${esc(r.name)}" data-mx-scope="${esc(r.scope)}">
952	      <td class="cell"><input type="checkbox" class="mx-pick" data-mx-kind="${kind}" data-mx-name="${esc(r.name)}" data-mx-base="${esc(mxRowBase(r))}" /></td>
953	      <td class="mx-scope-cell">${mxScopeCell(r)}</td>
954	      <td><span class="item-name item-name-link" data-view-content="${kind}" data-view-name="${esc(r.name)}" data-view-scope="${esc(r.scope)}" title="내용 보기">${esc(r.name)}</span>${rowErr}</td>
955	      <td>${tagChipsHtml(r.tags, r.autoTags)}</td>
956	      <td class="mx-tool">${mxToolCell(r.tools.claude)}</td>
957	      <td class="mx-tool">${mxToolCell(r.tools.codex)}</td>
958	      <td>${mxSyncCell(kind, r)}</td>
959	    </tr>`;
960	  }).join('');
961	  // 더보기(50행 단위).
962	  const more = $('#' + kind + '-mx-more');
963	  if (more) {
964	    more.innerHTML = shown.length < all.length
965	      ? `<span class="muted">${shown.length} / ${all.length}개 표시 중</span><button class="btn btn-ghost btn-sm" data-mx-more="${kind}">더보기 (+${Math.min(MX_PAGE, all.length - shown.length)})</button>`
966	      : (all.length > MX_PAGE ? `<span class="muted">${all.length}개 모두 표시됨</span>` : '');
967	  }
968	  const allc = $('#' + kind + '-mx-all'); if (allc) allc.checked = false;
969	  if ($('#' + kind + '-mx-progress')) $('#' + kind + '-mx-progress').textContent = '';
970	}
971	
972	// 상태 필터 칩 클릭.
973	function applyMxFilter(kind, key) {
974	  mxState[kind].filter = key;
975	  mxState[kind].page = 1;
976	  renderMxFilters(kind);
977	  renderMatrix(kind);
978	}
979	// 이름 검색 입력.
980	function applyMxSearch(kind, q) {
981	  mxState[kind].q = q;
982	  mxState[kind].page = 1;
983	  renderMatrix(kind);
984	}
985	// 더보기.
986	function mxMore(kind) { mxState[kind].page += 1; renderMatrix(kind); }
