988	async function doSkillPull(name, sourceId, piAck) {
989	  currentSkillPull = { name, source_id: sourceId }; currentPullTool = null; currentAgentPull = null; currentSync = null; currentStoreApply = null;
990	  const res = await fetch('/skills/pull', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ name, source_id: sourceId, piAck }) });
991	  if (res.status === 409) { showPiModal(await res.json()); return; } // PI 게이트 흐름 보존
992	  if (!res.ok) { toast('적용하지 못했습니다: ' + (await errMsg(res))); return; }
993	  await res.json();
994	  $('#pi-modal').hidden = true;
995	  toast('스킬 가져오기 완료');
996	  loadSkillOverview();
997	}
