999	// 슬라이드오버: 도구별 ov-card(.skills/diff?name=&to=) + push + 태그수정
1000	async function openSkillDetail(name) {
1001	  let d;
1002	  try {
1003	    d = await Promise.all(TOOLS.map((to) =>
1004	      api('/skills/diff?name=' + encodeURIComponent(name) + '&to=' + encodeURIComponent(to)).then((x) => ({ to, ...x }))
1005	    ));
1006	  } catch (e) { toast('상세를 불러오지 못했습니다: ' + e.message); return; }
1007	  const allLosses = [];
1008	  const cards = d.map((x) => {
1009	    (x.losses || []).forEach((l) => allLosses.push(`[${x.to}] ${l}`));
1010	    const changes = !x.canonicalExists ? '없음' : (x.hasChanges ? '변경 있음' : '동일');
1011	    return `<div class="ov-card">
1012	      <div class="ov-head"><span class="tool-dot" style="background:${TOOL_COLOR[x.to]}"></span>${x.to}</div>
1013	      <div class="ov-kv"><b>대상</b> <code>${esc((x.targetPath || '').split('/').slice(-2).join('/'))}</code></div>
1014	      <div class="ov-kv">상태: ${changes}</div>
1015	      <button class="btn btn-secondary btn-sm" data-skill-diff-name="${esc(name)}" data-skill-diff-to="${x.to}">diff 보기</button>
1016	      <button class="btn btn-secondary btn-sm" data-skill-apply="${esc(name)}" data-skill-apply-to="${x.to}" ${x.canonicalExists ? '' : 'disabled'}>적용</button>
1017	    </div>`;
1018	  }).join('');
1019	  const anyCanon = d.some((x) => x.canonicalExists);
1020	  openPanel({
1021	    title: name,
1022	    meta: '<span class="kv"><b>스킬 상세</b></span>',
1023	    bodyHtml: lossBanner(allLosses) + '<div class="sub-label">모델별 미리보기/적용</div><div class="overlay-grid">' + cards + '</div><div id="skill-apply-all-result"></div><div id="skill-inline-diff"></div>',
1024	    footHtml: `<button class="btn btn-primary" data-sync-open="skill" data-sync-name="${esc(name)}">동기화</button><button class="btn btn-secondary" data-skill-apply-all="${esc(name)}" ${anyCanon ? '' : 'disabled'}>중앙 저장소 → 세 모델</button><button class="btn btn-ghost" data-view-open="skill" data-view-name="${esc(name)}" data-view-scope="${esc(mxScopeOf('skill', name))}">내용 보기</button><button class="btn btn-ghost" data-tag-kind="skill" data-tag-id="${esc(name)}">태그 수정</button><button class="btn btn-ghost" id="panel-cancel">닫기</button>`,
1025	  });
1026	}
