1028	async function doSkillDiff(name, to) {
1029	  let d;
1030	  try { d = await api('/skills/diff?name=' + encodeURIComponent(name) + '&to=' + encodeURIComponent(to)); }
1031	  catch (e) { toast('미리보기를 불러오지 못했습니다: ' + e.message); return; }
1032	  let body;
1033	  if (!d.canonicalExists) body = '<div class="empty-state">중앙 저장소에 해당 skill이 없습니다.</div>';
1034	  else if (!d.hasChanges) body = '<div class="empty-state">차이 없음 — 이미 동일</div>';
1035	  else body = renderDiff(d.diff);
1036	  $('#skill-inline-diff').innerHTML = `<div class="divider-strong"></div><div class="sub-label">${esc(name)} → ${esc(to)}</div>${lossBanner(d.losses)}${body}`;
1037	  $('#skill-inline-diff').scrollIntoView({ behavior: 'smooth', block: 'nearest' });
1038	}
