1040	async function doSkillApply(name, to) {
1041	  // #2: 미리보기 패널(openSkillDetail)을 거친 적용 — native confirm() 제거.
1042	  try {
1043	    const r = await api('/skills/push', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ name, to, apply: true }) });
1044	    toast(`${to} 적용 완료 · 백업: ` + (r.backupPath || '(신규)'));
1045	    loadSkillOverview();
1046	    loadSyncLog();
