1063	// ===================== 에이전트(agents) — 상세/pull 핸들러(매트릭스는 loadMatrix가 렌더) =====================
1064	async function doAgentPull(from, name, piAck) {
1065	  currentAgentPull = { from, name }; currentPullTool = null; currentSkillPull = null; currentSync = null; currentStoreApply = null;
1066	  const res = await fetch('/agents/pull', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ from, name, piAck }) });
1067	  if (res.status === 409) { showPiModal(await res.json()); return; } // PI 게이트 흐름 보존
1068	  if (!res.ok) { toast('적용하지 못했습니다: ' + (await errMsg(res))); return; }
1069	  await res.json();
1070	  $('#pi-modal').hidden = true;
1071	  toast('에이전트 가져오기 완료');
