1075	// 슬라이드오버: 도구별 tstat + tools 칩 + loss-banner + diff + push
1076	async function openAgentDetail(id) {
1077	  let ag, d;
1078	  try {
1079	    ag = await api('/agents/overview');
1080	    d = await Promise.all(TOOLS.map((to) =>
