1089	    const reason = (x.losses || []).length ? `<div class="tstat-reason">손실: ${x.losses.map(esc).join(', ')}</div>` : '';
1090	    return `<div class="tstat-row">
1091	        <span class="tool-dot" style="background:${TOOL_COLOR[x.to]}"></span>
1092	        <span class="tool-name">${x.to}</span>
1093	        <span class="muted" style="margin-left:auto">${state}</span>
