1095	        <button class="btn btn-secondary btn-sm" data-agent-apply="${esc(id)}" data-agent-apply-to="${x.to}" ${x.canonicalExists ? '' : 'disabled'}>적용</button>
1096	      </div>${reason}`;
1097	  }).join('');
1098	  const toolChips = (meta.tools || []).map((t) => `<span class="tool-chip" style="color:${TOOL_COLOR[t] || 'var(--st-muted)'};background:${TOOL_SOFT[t] || 'var(--st-muted-soft)'}">${esc(t)}</span>`).join(' ');
1099	  const anyCanon = d.some((x) => x.canonicalExists);
1100	  openPanel({
1101	    title: meta.name,
1102	    meta: `<span class="kv"><b>출처</b> ${esc(meta.source_tool || '—')}</span>`,
1103	    bodyHtml: lossBanner(allLosses)
1104	      + (toolChips ? `<div class="sub-label">대상 모델</div><div class="chip-list">${toolChips}</div><div style="height:14px"></div>` : '')
1105	      + refSkillsSection(meta.name)
1106	      + '<div class="sub-label">모델별 상태</div><div class="tstat">' + rows + '</div><div id="agent-apply-all-result"></div><div id="agent-inline-diff"></div>',
1107	    footHtml: `<button class="btn btn-primary" data-sync-open="agent" data-sync-name="${esc(meta.name)}">동기화</button><button class="btn btn-secondary" data-agent-apply-all="${esc(id)}" ${anyCanon ? '' : 'disabled'}>중앙 저장소 → 세 모델</button><button class="btn btn-ghost" data-view-open="agent" data-view-name="${esc(meta.name)}" data-view-scope="${esc(mxScopeOf('agent', meta.name))}">내용 보기</button><button class="btn btn-ghost" data-tag-kind="agent" data-tag-id="${esc(id)}">태그 수정</button><button class="btn btn-ghost" id="panel-cancel">닫기</button>`,
1108	  });
1109	}
