1111	// F5: 에이전트 상세의 "참조 스킬" 섹션. 매트릭스 행(referencedSkills)에서 이름을 읽어
1112	// 스킬 뷰로 이동하는 링크 목록으로 렌더한다(공식 메커니즘: Claude frontmatter skills / Codex skills.config).
1113	// 참조가 없으면 "없음"만 간단히 표기.
1114	function agentRefSkills(name) {
1115	  const rows = (mxState.agent.data && mxState.agent.data.rows) || [];
1116	  const row = rows.find((r) => r.name === name);
1117	  return (row && row.referencedSkills) || [];
1118	}
1119	function refSkillsSection(name) {
1120	  const skills = agentRefSkills(name);
1121	  const inner = skills.length
1122	    ? `<div class="chip-list ref-skill-list">${skills.map((s) =>
1123	        `<button class="ref-skill-chip" data-ref-skill="${esc(s)}" title="스킬 뷰에서 '${esc(s)}' 보기">🧩 ${esc(s)}</button>`).join('')}</div>`
1124	    : `<div class="muted" style="font-size:13px;padding:2px 0">없음</div>`;
1125	  return `<div class="sub-label">참조 스킬</div>${inner}<div style="height:14px"></div>`;
1126	}
1127	
1128	// 참조 스킬 링크 클릭 → 스킬 뷰로 이동하고 이름 검색을 채운 상태로 보여준다(기존 showView + 검색 재사용).
