116	// 반환 행: { type:'same'|'change'|'left'|'right', left:{n,line}, right:{n,line} }
117	//   - 'same'  : 양쪽 동일한 줄(줄번호는 각 파일 기준 각각 부여).
118	//   - 'change': 연속 '-'(왼쪽만) 블록과 '+'(오른쪽만) 블록을 행 단위로 짝지음(removed[i]↔added[i]).
119	//   - 'left'  : 왼쪽에만 남는 줄(오른쪽은 filler: n=null,line=null).
120	//   - 'right' : 오른쪽에만 남는 줄(왼쪽은 filler: n=null,line=null).
121	// 줄번호(n)는 각 파일 기준 1부터. filler 쪽은 n=null,line=null.
122	// 순수 함수(디스크·네트워크 없음). intra-line(문자 단위) 하이라이트는 프런트 담당.
123	function sideBySide(leftText, rightText) {
124	  const d = lineDiff(leftText, rightText);
125	  const out = [];
126	  let ln = 0; // 왼쪽 줄번호 카운터
127	  let rn = 0; // 오른쪽 줄번호 카운터
128	
129	  // 연속된 '-'(removed)와 '+'(added) 블록을 모아 한 번에 짝지어 flush한다.
130	  let removed = [];
131	  let added = [];
132	  function flushBlock() {
133	    if (!removed.length && !added.length) return;
134	    const pairs = Math.min(removed.length, added.length);
135	    for (let i = 0; i < pairs; i++) {
136	      out.push({
137	        type: 'change',
138	        left: { n: ++ln, line: removed[i] },
139	        right: { n: ++rn, line: added[i] },
140	      });
141	    }
142	    // 남는 removed → left 행(오른쪽 filler)
143	    for (let i = pairs; i < removed.length; i++) {
144	      out.push({
145	        type: 'left',
146	        left: { n: ++ln, line: removed[i] },
147	        right: { n: null, line: null },
148	      });
149	    }
150	    // 남는 added → right 행(왼쪽 filler)
151	    for (let i = pairs; i < added.length; i++) {
152	      out.push({
153	        type: 'right',
154	        left: { n: null, line: null },
155	        right: { n: ++rn, line: added[i] },
156	      });
157	    }
158	    removed = [];
159	    added = [];
160	  }
161	
162	  for (const row of d) {
163	    if (row.type === ' ') {
164	      flushBlock();
165	      out.push({
166	        type: 'same',
167	        left: { n: ++ln, line: row.line },
168	        right: { n: ++rn, line: row.line },
169	      });
170	    } else if (row.type === '-') {
171	      removed.push(row.line);
172	    } else {
173	      added.push(row.line);
174	    }
175	  }
