input.old_string:
// ===================== 개요(overview, 첫 화면) — D27 동기화 중심 =====================
// 최상단 stat = 동기화 요약(불일치·일부 없음·동기화됨·프로젝트). 두 매트릭스 counts를 합산한다.
async function loadOverview() {
  showLoading('#ov-stats');
  // 두 kind 매트릭스를 병렬 fetch(개요가 무거워지지 않게). 프로젝트 수는 /projects로.
  // (이슈1) fetchMatrix로 받아 mxState 캐시에 저장 — 시작 배지(initNavCounts)·스킬/에이전트 뷰와
  //   in-flight/캐시를 공유해 같은 matrix를 여러 번 fetch하지 않는다.
  // allSettled: 하나가 실패해도 나머지는 렌더된다(우아한 실패, D26-②).
  // 에이전트 뷰 숨김(D32) 이후 개요는 스킬 매트릭스만 집계한다.
  const settled = await Promise.allSettled([
    fetchMatrix('skill'), api('/projects'),
  ]);
  if (settled.every((s) => s.status === 'rejected')) {
    showLoadError('#ov-stats', loadOverview);
    return;
  }
  const val = (i, dflt) => (settled[i].status === 'fulfilled' ? settled[i].value : dflt);
  const mSkill = val(0, { counts: {}, rows: [] }), proj = val(1, { projects: [] });

  const sc = mSkill.counts || {};
  const drift = sc.drift || 0, partial = sc.partial || 0, synced = sc.synced || 0, single = sc.single || 0;
  const projectCount = (proj.projects || []).length;
  const skillCount = (mSkill.rows || []).length;
  const total = skillCount;
  const attention = drift + partial;

  setCount('skills', skillCount);

  const guide = $('#ov-guide');
  if (guide) {
    guide.innerHTML = `<div class="action-guide">
      <div>
        <div class="ag-title">오늘 할 일: ${attention ? `동기화 필요한 항목 ${attention}개부터 정리` : '새 스킬을 찾거나 프로젝트를 연결'}</div>
        <div class="ag-sub">중앙 원본은 Claude/Codex에 내보내기 전 기준점입니다. 모든 변경은 미리보기와 백업을 거칩니다.</div>
      </div>
      <div class="ag-acts">
        <button class="btn btn-secondary btn-sm" data-goto="skills">동기화 상태 보기</button>
        <button class="btn btn-ghost btn-sm" data-goto="store">새 스킬 찾기</button>
        <button class="btn btn-ghost btn-sm" data-open-projects="1">프로젝트 연결</button>
      </div>
    </div>`;
  }

  // 온보딩 카드: 스킬이 하나도 없을 때(중앙 저장소 언급 제거, 매트릭스 관점).
  const onboard = $('#ov-onboard');
  if (onboard) {
    if (total === 0) {
      onboard.hidden = false;
      onboard.innerHTML = `<div class="onboard-card">
        <div class="onboard-ic">👋</div>
        <div class="onboard-body">
          <div class="onboard-title">아직 스킬이 하나도 없어요.</div>
          <div class="onboard-steps">① 스토어에서 추천 스킬 적용 · ② 프로젝트를 추가하면 그 안의 스킬도 자동으로 보입니다</div>
          <div class="inline-acts" style="margin-top:12px">
            <button class="btn btn-primary btn-sm" data-goto="store">스토어 보기</button>
            <button class="btn btn-secondary btn-sm" data-open-projects="1">📁 프로젝트 관리</button>
          </div>
        </div>
      </div>`;
    } else {
      onboard.hidden = true;
      onboard.innerHTML = '';
    }
  }

  // 4 stat 카드 (하나는 hero) — 동기화 요약. 클릭 시 스킬 뷰 주의 필터로.
  const stats = [
    { label: '불일치', num: drift, trend: '내용이 서로 다름 — 동기화 필요', view: 'skills', hero: true },
    { label: '일부 없음', num: partial, trend: '일부 모델에만 있음', view: 'skills' },
    { label: '동기화됨', num: synced, trend: '모든 모델이 동일', view: 'skills' },
    { label: '프로젝트', num: projectCount, trend: '자동 발견 + 직접 추가', view: 'skills', projects: true },
  ];
  $('#ov-stats').innerHTML = stats.map((s) => `
    <button class="stat ${s.hero ? 'hero' : ''}" ${s.projects ? 'data-open-projects="1"' : `data-goto="${s.view}"`}>
      <div class="stat-head"><span class="stat-label">${esc(s.label)}</span><span class="stat-corner">→</span></div>
      <div class="stat-num">${esc(String(s.num))}</div>
      <div class="stat-trend">${esc(s.trend)}</div>
    </button>`).join('');

  // 타입 분포(동기화 대상 항목 수). 에이전트는 뷰 숨김(D32)으로 집계 제외.
  const dist = [
    { ic: '🧩', label: '스킬', n: skillCount },
    { ic: '🔗', label: '단독(1곳만)', n: single },
  ];
  const maxN = Math.max(1, ...dist.map((d) => d.n));
  $('#ov-dist').innerHTML = dist.map((d) => `
    <div class="dist-row">
      <span class="dist-ic">${d.ic}</span>
      <span class="dist-label">${esc(d.label)}</span>
      <span class="dist-bar"><div style="width:${Math.round((d.n / maxN) * 100)}%"></div></span>
      <span class="dist-num">${d.n}</span>
    </div>`).join('');

  // 마지막 동기화/점검 (독립 위젯 — 실패해도 개요 나머지는 유지)
  try {
    const s = await api('/synclog');
    $('#ov-lastsync').innerHTML = lastSyncHtml(s);
  } catch {
    showLoadError('#ov-lastsync', loadOverview);
  }
}

input.new_string:
// ===================== 개요(overview, 첫 화면) — 스킬 상태 요약 =====================
// 4 stat = 스킬 개수 · 지난 1일 수정 · 지난 7일 수정 · 동기화 필요.
// "수정"은 매트릭스 rows[].lastModified(ISO|null) 기준(사용/호출 데이터 없음 — 부제에 명시).
// 분포는 categoryCounts로 뽑은 상위 5 카테고리 순위 목록으로 교체.
async function loadOverview() {
  showLoading('#ov-stats');
  // 스킬 매트릭스만 fetch(에이전트·스토어 뷰 숨김, D32). 프로젝트 수는 액션 가이드용.
  // (이슈1) fetchMatrix로 받아 mxState 캐시에 저장 — 시작 배지·스킬 뷰와 in-flight/캐시 공유.
  // allSettled: 하나가 실패해도 나머지는 렌더된다(우아한 실패, D26-②).
  const settled = await Promise.allSettled([
    fetchMatrix('skill'), api('/projects'),
  ]);
  if (settled.every((s) => s.status === 'rejected')) {
    showLoadError('#ov-stats', loadOverview);
    return;
  }
  const val = (i, dflt) => (settled[i].status === 'fulfilled' ? settled[i].value : dflt);
  const mSkill = val(0, { counts: {}, rows: [] }), proj = val(1, { projects: [] });

  const rows = mSkill.rows || [];
  const skillCount = rows.length;
  // "수정" 집계: lastModified(ISO 문자열|null)를 파싱해 now 기준 창 안에 드는 행 수.
  const now = Date.now();
  const DAY = 86400000;
  const modifiedWithin = (ms) => rows.filter((r) => {
    if (!r.lastModified) return false;
    const t = new Date(r.lastModified).getTime();
    return !Number.isNaN(t) && (now - t) <= ms && (now - t) >= 0;
  }).length;
  const mod1 = modifiedWithin(DAY);
  const mod7 = modifiedWithin(7 * DAY);
  // 동기화 필요 = syncState !== 'synced'(불일치·일부없음·단독 모두 포함).
  const needSync = rows.filter((r) => r.syncState !== 'synced').length;
  const projectCount = (proj.projects || []).length;

  setCount('skills', skillCount);

  const guide = $('#ov-guide');
  if (guide) {
    guide.innerHTML = `<div class="action-guide">
      <div>
        <div class="ag-title">오늘 할 일: ${needSync ? `동기화 필요한 스킬 ${needSync}개부터 정리` : '스킬이 모두 맞춰져 있어요'}</div>
        <div class="ag-sub">모든 변경은 미리보기와 백업을 거칩니다. 스킬 상태와 최근 수정을 아래에서 확인하세요.</div>
      </div>
      <div class="ag-acts">
        <button class="btn btn-secondary btn-sm" data-goto="skills">스킬 상태 보기</button>
        <button class="btn btn-ghost btn-sm" data-open-projects="1">프로젝트 연결</button>
      </div>
    </div>`;
  }

  // 온보딩 카드: 스킬이 하나도 없을 때(스토어 링크 제거 — 뷰 숨김).
  const onboard = $('#ov-onboard');
  if (onboard) {
    if (skillCount === 0) {
      onboard.hidden = false;
      onboard.innerHTML = `<div class="onboard-card">
        <div class="onboard-ic">👋</div>
        <div class="onboard-body">
          <div class="onboard-title">아직 스킬이 하나도 없어요.</div>
          <div class="onboard-steps">프로젝트를 추가하면 그 안의 스킬도 자동으로 보입니다.</div>
          <div class="inline-acts" style="margin-top:12px">
            <button class="btn btn-secondary btn-sm" data-open-projects="1">📁 프로젝트 관리</button>
          </div>
        </div>
      </div>`;
    } else {
      onboard.hidden = true;
      onboard.innerHTML = '';
    }
  }

  // 4 stat 카드 (하나는 hero). 부제에 "최근 수정 기준"임을 명시(사용/호출 데이터 없음).
  const stats = [
    { label: '스킬 개수', num: skillCount, trend: '모델 간 동기화 대상 전체', view: 'skills', hero: true },
    { label: '지난 1일 수정', num: mod1, trend: '최근 수정 기준 · 24시간 이내', view: 'skills' },
    { label: '지난 7일 수정', num: mod7, trend: '최근 수정 기준 · 7일 이내', view: 'skills' },
    { label: '동기화 필요', num: needSync, trend: '아직 두 모델이 다름', view: 'skills' },
  ];
  $('#ov-stats').innerHTML = stats.map((s) => `
    <button class="stat ${s.hero ? 'hero' : ''}" data-goto="${s.view}">
      <div class="stat-head"><span class="stat-label">${esc(s.label)}</span><span class="stat-corner">→</span></div>
      <div class="stat-num">${esc(String(s.num))}</div>
      <div class="stat-trend">${esc(s.trend)}</div>
    </button>`).join('');

  // 카테고리 TOP 5 순위(가장 스킬 수 많은 카테고리). categoryCounts(tags+autoTags+미정 집계)
  // 를 내림차순 상위 5개로. 동점은 라벨순, 5개 미만/0개도 우아하게.
  const counts = categoryCounts(rows);
  const ranked = Object.entries(counts)
    .map(([key, n]) => ({ key, n, label: key === UNTAGGED_KEY ? '미정' : catLabel(key) }))
    .sort((a, b) => (b.n - a.n) || (a.label < b.label ? -1 : a.label > b.label ? 1 : 0))
    .slice(0, 5);
  const dist = $('#ov-dist');
  if (dist) {
    dist.innerHTML = ranked.length
      ? ranked.map((r, i) => `
        <div class="dist-row rank-row">
          <span class="dist-rank">${i + 1}</span>
          <span class="dist-label">${esc(r.label)}</span>
          <span class="dist-num">${r.n}</span>
        </div>`).join('')
      : '<div class="empty-state" style="padding:16px">아직 분류된 스킬이 없습니다.</div>';
  }

  // 마지막 동기화/점검 (독립 위젯 — 실패해도 개요 나머지는 유지)
  try {
    const s = await api('/synclog');
    $('#ov-lastsync').innerHTML = lastSyncHtml(s);
  } catch {
    showLoadError('#ov-lastsync', loadOverview);
  }
}

