// 지시문 뷰 = 좌우 큰 화면(과제3). GET /instr/content 소비.
//  · synced(sideBySide=null): 단일 본문 + "두 지시문이 동일합니다" + 동기화 버튼 비활성.
//  · drift(sideBySide 있음): renderSideBySide 좌우 diff + 기준 선택(→ 기존 openInstrSync).
//  · partial/none: 있는 쪽 본문 + 없는 쪽 "파일 없음" 안내(기준 동기화 시 생성).
//  · readError/PI(409): 안내+재시도 / 기존 PI 모달. 크래시 금지.
let instrContentData = null; // 마지막 /instr/content(기준 선택 시 라벨/경로 참조).

async function loadInstructions(piAck) {
  showLoading('#instr-cards');
  $('#instr-summary').innerHTML = '';
  const qs = '/instr/content' + (piAck ? '?piAck=' + encodeURIComponent(piAck) : '');
  const res = await fetch(qs);
  if (res.status === 409) {
    // PI 게이트: 기존 PI 모달(마스킹 후 보기/취소) 재사용. 진행 컨텍스트를 지시문 콘텐츠로 표시.
    currentInstrContentAck = true;
    showPiModal(await res.json().catch(() => ({})));
    return;
  }
  if (!res.ok) { showLoadError('#instr-cards', () => loadInstructions()); return; }
  let m;
  try { m = await res.json(); }
  catch { showLoadError('#instr-cards', () => loadInstructions()); return; }
  currentInstrContentAck = false;
  renderInstrContent(m);
}

let currentInstrContentAck = false; // PI 모달 ack이 지시문 콘텐츠 재조회로 향해야 하는지.

function renderInstrContent(m) {
  instrContentData = m;
  const models = m.models || {};
  const present = TOOLS.filter((t) => models[t] && models[t].exists);
  setCount('instructions', present.length);
  const state = INSTR_STATE[m.syncState] || INSTR_STATE.none;

  // 읽기 실패가 하나라도 있으면 안내 + 다시 시도(전체 재로드).
  const readErr = TOOLS.find((t) => models[t] && models[t].readError);

  $('#instr-summary').innerHTML =
    `<div class="instr-summary-inner">
      <span class="badge ${state.badge}">${state.ic} ${esc(state.ko)}</span>
      <span class="instr-summary-desc">${esc(state.desc)}</span>
    </div>`;

  const box = $('#instr-cards');
  if (readErr) {
    box.innerHTML = `<div class="empty-state">지시문 파일을 읽지 못했습니다.
      <span class="inline-acts" style="justify-content:center;margin-top:10px">
        <button class="btn btn-secondary btn-sm" data-instr-retry="1">다시 시도</button>
      </span></div>`;
    return;
  }

  const claude = models.claude || { exists: false, path: '', body: null };
  const codex = models.codex || { exists: false, path: '', body: null };

  // drift: 좌우 diff + 기준 선택.
  if (m.sideBySide) {
    box.innerHTML = renderSideBySide(m.sideBySide, {
      leftLabel: 'claude', rightLabel: 'codex',
      leftTool: 'claude', rightTool: 'codex',
      leftPath: claude.path || INSTR_FILE.claude,
      rightPath: codex.path || INSTR_FILE.codex,
      onPickBase: true, // 기준 선택 버튼 → data-sxs-base 클릭이 openInstrSync를 부른다.
    });
    return;
  }

  // synced: 두 본문 동일 → 단일 본문 + 동일 안내(동기화 버튼 비활성).
  if (m.syncState === 'synced' && present.length === 2) {
    const body = claude.exists ? claude.body : codex.body;
    box.innerHTML =
      `<div class="instr-single">
        <div class="instr-single-head">
          <span class="loss-banner ok" style="flex:1"><span class="lb-ic">✓</span><div class="lb-txt">두 지시문이 <b>동일합니다</b> — 동기화할 것이 없습니다.</div></span>
          <button class="btn btn-secondary btn-sm" disabled title="이미 두 모델이 동일합니다">동기화</button>
        </div>
        <div class="instr-single-path">${esc(claude.path || codex.path || '')}</div>
        <pre class="viewer-pre">${esc(body || '')}</pre>
      </div>`;
    return;
  }

  // partial/none: 있는 쪽 본문 + 없는 쪽 "파일 없음". 기준 버튼으로 없는 쪽 생성 유도.
  const paneHtml = (tool, slot) => {
    const file = slot.path || INSTR_FILE[tool] || '';
    if (slot.exists) {
      return `<div class="instr-pane">
        <div class="instr-pane-head">
          <span class="tool-dot" style="background:${TOOL_COLOR[tool]}"></span>
          <span class="instr-pane-name">${esc(tool)}</span>
          <span class="instr-pane-path" title="${esc(file)}">${esc(file)}</span>
          <button class="btn btn-primary btn-sm" data-instr-base="${esc(tool)}">이 모델을 기준으로 동기화</button>
        </div>
        <pre class="viewer-pre">${esc(slot.body || '')}</pre>
      </div>`;
    }
    return `<div class="instr-pane absent">
      <div class="instr-pane-head">
        <span class="tool-dot" style="background:${TOOL_COLOR[tool]}"></span>
        <span class="instr-pane-name">${esc(tool)}</span>
        <span class="instr-pane-path" title="${esc(file)}">${esc(file)}</span>
      </div>
      <div class="empty-state">파일 없음 — 다른 모델을 기준으로 동기화하면 생성됩니다.</div>
    </div>`;
  };
  box.innerHTML = `<div class="instr-panes">${paneHtml('claude', claude)}${paneHtml('codex', codex)}</div>`;
}

