/* ===========================================================================
   과제1: 개요 카테고리 TOP 5 순위 목록 (dist 위젯 재사용)
   =========================================================================== */
.dist-row.rank-row { grid-template-columns: 24px 1fr 40px; }
.dist-rank {
  font-size: 13px; font-weight: 700; color: var(--st-muted);
  font-variant-numeric: tabular-nums; text-align: center;
}
.rank-row:first-child .dist-rank { color: var(--color-primary); }

/* ===========================================================================
   과제2: 좌우(side-by-side) diff 컴포넌트 — 지시문·스킬 공용(.sxs-*)
   전문 머지툴 스타일: 다른 줄=연한 빨강 배경, 바뀐 문자=진한 빨강,
   한쪽만 있는 줄=반대쪽 빗금(hatched), 가운데(상단) 기준 선택 버튼.
   =========================================================================== */
.sxs-basebar {
  display: flex; align-items: center; gap: 12px; flex-wrap: wrap;
  padding: 12px 14px; margin-bottom: 12px;
  background: var(--color-canvas-parchment); border: 1px solid var(--color-hairline);
  border-radius: var(--radius-lg);
}
.sxs-base-hint { font-size: 12.5px; color: var(--st-muted); flex: 1; text-align: center; min-width: 140px; }
.sxs {
  border: 1px solid var(--color-hairline); border-radius: var(--radius-lg);
  overflow: hidden; background: var(--color-canvas);
}
.sxs-headrow, .sxs-line { display: grid; grid-template-columns: 1fr 1fr; }
.sxs-headrow { border-bottom: 1px solid var(--color-hairline); background: var(--color-canvas-parchment); }
.sxs-head {
  display: flex; align-items: center; gap: 8px; min-width: 0;
  padding: 9px 12px; font-size: 13px; font-weight: 600;
}
.sxs-head:first-child { border-right: 1px solid var(--color-hairline); }
.sxs-head-name { text-transform: capitalize; }
.sxs-head-path {
  font-family: ui-monospace, Menlo, monospace; font-size: 11px; font-weight: 400; color: var(--st-muted);
  white-space: nowrap; overflow: hidden; text-overflow: ellipsis; margin-left: auto; max-width: 60%;
}
.sxs-body { max-height: 64vh; overflow: auto; }
.sxs-cell {
  display: flex; align-items: flex-start; gap: 8px; min-width: 0;
  padding: 1px 10px; font-family: ui-monospace, Menlo, monospace; font-size: 12.5px; line-height: 1.7;
}
.sxs-cell:first-child { border-right: 1px solid var(--color-hairline); }
.sxs-num {
  flex: none; width: 34px; text-align: right; color: var(--st-muted);
  font-size: 11px; user-select: none; padding-top: 1px;
}
.sxs-code { white-space: pre-wrap; overflow-wrap: anywhere; min-width: 0; flex: 1; }
/* 다른 줄(change): 양쪽 연한 빨강 배경. */
.sxs-cell.chg { background: var(--st-error-soft); }
/* 바뀐 문자 단위 하이라이트: 더 진한 빨강. */
.sxs-ch { background: color-mix(in srgb, var(--st-error) 34%, transparent); border-radius: 3px; padding: 0 1px; }
/* 한쪽만 있는 줄: 있는 쪽은 연한 빨강, 반대쪽(filler)은 빗금 채움으로 정렬 유지. */
.sxs-cell.only { background: var(--st-error-soft); }
.sxs-cell.filler {
  background-image: repeating-linear-gradient(
    45deg, transparent, transparent 5px,
    color-mix(in srgb, var(--st-muted) 22%, transparent) 5px,
    color-mix(in srgb, var(--st-muted) 22%, transparent) 6px);
}
@media (max-width: 1023.98px) {
  .sxs-body { max-height: 70vh; }
  .sxs-head-path { display: none; }
}

/* ===========================================================================
   과제3: 지시문 뷰 = 좌우 큰 화면 (단일 동일 본문 / 한쪽만 있음 2단)
   =========================================================================== */
.instr-single { display: flex; flex-direction: column; gap: 12px; }
.instr-single-head { display: flex; align-items: center; gap: 12px; }
.instr-single-path { font-family: ui-monospace, Menlo, monospace; font-size: 11.5px; color: var(--st-muted); }
.instr-panes { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; }
@media (max-width: 860px) { .instr-panes { grid-template-columns: 1fr; } }
.instr-pane {
  border: 1px solid var(--color-hairline); border-radius: var(--radius-lg);
  overflow: hidden; display: flex; flex-direction: column;
}
.instr-pane.absent { border-style: dashed; background: var(--color-canvas-parchment); }
.instr-pane-head {
  display: flex; align-items: center; gap: 8px; flex-wrap: wrap;
  padding: 10px 12px; border-bottom: 1px solid var(--color-hairline);
  background: var(--color-canvas-parchment); font-size: 13px; font-weight: 600;
}
.instr-pane.absent .instr-pane-head { border-bottom: none; }
.instr-pane-name { text-transform: capitalize; }
.instr-pane-path {
  font-family: ui-monospace, Menlo, monospace; font-size: 11px; font-weight: 400; color: var(--st-muted);
  white-space: nowrap; overflow: hidden; text-overflow: ellipsis; margin-left: auto; max-width: 50%;
}
.instr-pane-head .btn { margin-left: auto; }
.instr-pane-path + .btn { margin-left: 8px; }
.instr-pane .viewer-pre { margin: 12px; }

